DELETE FROM BOARD_LIKE_TBL
WHERE BOARD_NO = #{boardNo}
AND MEMBER_ID = #{memberId}

mapper.select:
SELECT COUNT(*)
FROM BOARD_LIKE_TBL
WHERE BOARD_NO = #{boardNo}
AND MEMBER_ID = #{memberId}

mapper.update:

UPDATE BOARD_COMMENT_TBL
SET BOARD_COMMENT_CONTENT = #{content},
    UPDATED_AT = SYSDATE,
    IS_SECRET = CASE WHEN #{isSecret} = 1 THEN 'Y' ELSE 'N' END
WHERE BOARD_COMMENT_NO = #{commentNo}
  AND BOARD_COMMENT_WRITER = #{memberId}

mapper.delete:
DELETE FROM BOARD_COMMENT_TBL
WHERE BOARD_COMMENT_NO = #{commentNo}
  AND BOARD_COMMENT_WRITER = #{memberId}

mapper.insert:
	-- 스크랩 추가 기능임. 이미 스크랩한 기록이 있으면 또 추가 안 함
    insert into tip_tbl (board_no, member_id)
    select #{boardNo}, #{memberId}
    from dual
    where not exists (
        select 1 from tip_tbl where board_no = #{boardNo} and member_id = #{memberId}
    )

mapper.update:
UPDATE MEMBER_POINT_TBL
SET TOTAL_POINT = TOTAL_POINT + 5
WHERE MEMBER_ID = #{memberId}

mapper.select:
select r.report_no, r.target_no, r.target_type, r.member_id, r.report_category, r.report_content, r.report_date, r.report_status,
case when r.target_type = 'board' then b.board_title when r.target_type = 'comment' then c.board_comment_content end as targetTitle,
case when r.target_type = 'board' then b.writer_id when r.target_type = 'comment' then c.board_comment_writer end as targetId,
case when r.target_type = 'board' then r.target_no when r.target_type = 'comment' then c.board_no end as boardNo,
(select count(*) from report_tbl where target_no = r.target_no and target_type = r.target_type) as reportCount
from report_tbl r inner join (
select target_no, target_type, min(report_no) as first_report_no from report_tbl group by target_no, target_type ) g on r.report_no = g.first_report_no
left join board_tbl b on r.target_no = b.board_no and r.target_type = 'board' left join board_comment_tbl c on r.target_no = c.board_comment_no and r.target_type = 'comment'
and r.target_type = #{type}
and r.report_category = #{category}
and r.report_status = #{status}
order by reportCount ${sortOrder}, r.report_status asc
order by r.report_status asc, r.report_date ${sortOrder}
